checker_dsl:
EXISTS (`EqualsMethod M`) {
  AND {
    EXISTS (`Parameter P`) {
      AND {
        (`P is a parameter of method M`),
        NOT {
          EXISTS (`InstanceOfExpr IOE`) {
            (`the expression of IOE is an access to variable P`)
          }
        },
        NOT {
          EXISTS (`NotInstanceOfExpr NIOE`) {
            (`the expression of NIOE is an access to variable P`)
          }
        },
        NOT {
          EXISTS (`SafeCastExpr SCE`) {
            (`the expression of SCE is an access to variable P`)
          }
        },
        NOT {
          EXISTS (`ClassExpr CE`) {
            (`the expression of CE is an access to variable P`)
          }
        },
        NOT {
          EXISTS (`MethodCall MA1`) {
            AND {
              (`the name of the method called by MA1 is "getClass"`),
              (`the qualifier of MA1 is an access to variable P`)
            }
          }
        },
        NOT {
          EXISTS (`CheckedCast CC`) {
            (`the expression of CC is an access to variable P`)
          }
        },
        NOT {
          EXISTS (`Parameter P2`, `MethodCall MA2`) {
            AND {
              EXISTS (`InstanceOfExpr IOE2`) {
                (`the expression of IOE2 is an access to variable P2`)
              },
              (`an access to variable P is an argument in the call MA2 that corresponds to parameter P2`)
            }
          }
        },
        NOT {
          EXISTS (`MethodCall MA3`) {
            AND {
              (`the method called by MA3 has no body`),
              (`an access to variable P is an argument of the call MA3`)
            }
          }
        }
      }
    },
    NOT {
      EXISTS (`BlockStmt B`, `ReturnStmt RET`, `EQExpr EQ`) {
        AND {
          (`the expression of return statement RET is EQ`),
          EXISTS (`Access A1`, `Access A2`) {
            AND {
              (`A1 is an operand of EQ`),
              (`A2 is an operand of EQ`),
              (`A1 is an access to a parameter of method M`),
              OR {
                (`A2 is a ThisAccess`),
                (`A2 is a FieldAccess`)
              }
            }
          }
        }
      }
    },
    NOT {
      EXISTS (`ThrowStmt TS`) {
        (`TS is inside the body of method M`)
      }
    }
  }
}
